package main

import "fmt"

// We declare that his function WILL return an 'int'
func multiply(a int, b int) int {
    result := a * b
    return result
}

func main() {
    // We capture the returned answer into a variable!
    total := multiply(5, 5)

    fmt.Println("5 x 5 is", total)
}
